// // This module is designed to shift a single '1' on every negative clock edge and has an asynchronous reset.
module ring_counter (
    input clk,
    input reset,
    output reg [4:0] count
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 5'b00001;
        end else begin
            count <= {count[3:0], count[4]};
        end
    end
endmodule
